import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Camera, MapPin, Loader2 } from 'lucide-react';
import API from '../../services/api';
import { useLocation } from '../../hooks/useLocation';

export default function ReportAnimal() {
  const coords = useLocation();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [file, setFile] = useState(null);

  const submitReport = async (e) => {
    e.preventDefault();
    setLoading(true);
    const fd = new FormData();
    fd.append('image', file);
    fd.append('animalType', e.target.type.value);
    fd.append('latitude', coords.lat);
    fd.append('longitude', coords.lng);

    try {
      const res = await API.post('/incidents', fd);
      navigate('/waiting');
    } catch (err) { alert("Report failed"); }
    setLoading(false);
  };

  return (
    <div className="max-w-md mx-auto p-6">
      <h1 className="text-2xl font-bold mb-6">Emergency Details</h1>
      <form onSubmit={submitReport} className="space-y-4">
        <select name="type" className="w-full p-4 border rounded-2xl">
          <option>Dog</option><option>Cat</option><option>Cow</option>
        </select>
        <div className="border-2 border-dashed p-10 text-center rounded-2xl">
          <input type="file" onChange={(e)=>setFile(e.target.files[0])} required />
          <Camera className="mx-auto mt-2 text-gray-400" />
        </div>
        <button className="w-full bg-red-600 text-white py-4 rounded-2xl font-bold text-lg">
          {loading ? <Loader2 className="animate-spin mx-auto"/> : "SUBMIT EMERGENCY"}
        </button>
      </form>
    </div>
  );
}
